-- Create tables if not exist (idempotent)
CREATE TABLE IF NOT EXISTS adoff_autopilot.budget_alerts (
  id SERIAL PRIMARY KEY,
  timestamp TIMESTAMPTZ DEFAULT NOW(),
  severity TEXT NOT NULL CHECK (severity IN ('warning', 'critical')),
  daily_cost_eur NUMERIC(10,2),
  monthly_cost_eur NUMERIC(10,2),
  n_calls_24h INTEGER,
  message TEXT,
  created_at TIMESTAMPTZ DEFAULT NOW()
);

CREATE TABLE IF NOT EXISTS adoff_autopilot.workflow_kill_switch (
  id SERIAL PRIMARY KEY,
  workflow_id TEXT UNIQUE NOT NULL,
  disabled BOOLEAN DEFAULT false,
  reason TEXT,
  set_at TIMESTAMPTZ DEFAULT NOW()
);

-- Ensure indexes
CREATE INDEX IF NOT EXISTS idx_budget_alerts_severity ON adoff_autopilot.budget_alerts(severity);
CREATE INDEX IF NOT EXISTS idx_budget_alerts_timestamp ON adoff_autopilot.budget_alerts(timestamp DESC);
CREATE INDEX IF NOT EXISTS idx_workflow_kill_switch_workflow_id ON adoff_autopilot.workflow_kill_switch(workflow_id);

