// Aggregate daily + monthly costs, convert USD to EUR
const daily_items = $('Query daily cost').getAll();
const monthly_items = $('Query monthly cost').getAll();

let daily_cost_usd = 0, monthly_cost_usd = 0, n_calls_24h = 0;

for (const item of daily_items) {
  daily_cost_usd += parseFloat(item.json.cost_usd_24h || 0);
  n_calls_24h += parseInt(item.json.n_calls_24h || 0);
}

for (const item of monthly_items) {
  monthly_cost_usd += parseFloat(item.json.cost_usd_month || 0);
}

const daily_cost_eur = daily_cost_usd * 0.92;
const monthly_cost_eur = monthly_cost_usd * 0.92;

return [{
  json: {
    daily_cost_usd: parseFloat(daily_cost_usd.toFixed(4)),
    daily_cost_eur: parseFloat(daily_cost_eur.toFixed(4)),
    monthly_cost_usd: parseFloat(monthly_cost_usd.toFixed(4)),
    monthly_cost_eur: parseFloat(monthly_cost_eur.toFixed(4)),
    n_calls_24h: n_calls_24h,
    timestamp: new Date().toISOString(),
    threshold_warning_eur: 2,
    threshold_critical_eur: 5,
    threshold_critical_monthly_eur: 30
  }
}];

